// ╔══════════════════════════════════════════════════════════╗
// ║  GANTI 6 NILAI INI - tidak perlu ubah node yang lain    ║
// ╚══════════════════════════════════════════════════════════╝

global.set('fitflow', {

  // URL app FitFlow (Vercel production)
  base_url:     'https://fitflow-coach-theta.vercel.app',

  // Sama persis dengan NODERED_WEBHOOK_SECRET di .env Vercel
  secret:       'GANTI_NODERED_WEBHOOK_SECRET',

  // Token API Fonnte (fonnte.com → Dashboard → Token API)
  fonnte_token: 'GANTI_TOKEN_FONNTE',

  // Supabase user ID instruktur
  // → FitFlow app → Settings → salin dari URL Supabase atau Supabase Dashboard → Auth → Users
  user_id:      'GANTI_UUID_INSTRUKTUR',

  // Nomor WA instruktur untuk terima rekap pagi & notif pendaftar
  // Format: 628 + nomor tanpa 0 depan (contoh: 6281234567890)
  instr_phone:  '628xxxxxxxxxxxx',

  // Sama persis dengan FONNTE_WEBHOOK_KEY di .env Vercel
  fonnte_key:   'GANTI_FONNTE_WEBHOOK_KEY'

});

const cfg = global.get('fitflow');
node.status({ fill: 'green', shape: 'dot', text: '✅ Config aktif - ' + cfg.base_url });
node.warn('FitFlow config dimuat: ' + JSON.stringify(cfg));
return null;

const cfg = global.get('fitflow') || {};
msg.url     = cfg.base_url + '/api/webhooks/nodered';
msg.method  = 'GET';
msg.headers = { 'x-webhook-secret': cfg.secret };
return msg;

const cfg = global.get('fitflow') || {};
msg.url     = cfg.base_url + '/api/webhooks/nodered';
msg.method  = 'POST';
msg.headers = { 'x-webhook-secret': cfg.secret, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({ action: 'refresh_statuses' });
return msg;

const cfg = global.get('fitflow') || {};
msg.url     = cfg.base_url + '/api/webhooks/nodered';
msg.method  = 'POST';
msg.headers = { 'x-webhook-secret': cfg.secret, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({ action: 'get_stats', user_id: cfg.user_id });
return msg;

const cfg  = global.get('fitflow') || {};
const data = msg.payload;

if (!data || !data.ok || !data.stats) {
  node.warn('get_stats gagal: ' + JSON.stringify(data));
  return null;
}

const s = data.stats;
const rupiah = n => 'Rp ' + Number(n || 0).toLocaleString('id-ID');

const tgl = new Date().toLocaleDateString('id-ID', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

let sessionLines = '  (tidak ada sesi hari ini)';
if (s.sessions && s.sessions.length > 0) {
  sessionLines = s.sessions.map(ses => {
    const jam = (ses.start_time || '').slice(0, 5);
    return '  • ' + ses.class_name + (jam ? ' ' + jam : '') +
      ' - ' + (ses.attended_count || 0) + ' hadir, ' + rupiah(ses.session_revenue);
  }).join('\n');
}

const pesan =
  '📊 *Rekap Harian FitFlow*\n' +
  tgl + '\n\n' +
  '🏋️‍♀️ Sesi hari ini: *' + s.sessions_today + '*\n' +
  '👥 Total hadir: *' + s.attended_today + ' orang*\n' +
  '💰 Pendapatan: *' + rupiah(s.revenue_today) + '*\n' +
  '⏳ Menunggu konfirmasi: *' + s.pending_payments + '*\n' +
  '⚠️ Perlu Follow Up: *' + s.at_risk_members + ' member*\n\n' +
  'Detail sesi:\n' + sessionLines;

let phone = (cfg.instr_phone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

msg.url     = 'https://api.fonnte.com/send';
msg.method  = 'POST';
msg.headers = { 'Authorization': cfg.fonnte_token, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({ target: phone, message: pesan, countryCode: '62' });
return msg;

const cfg = global.get('fitflow') || {};
msg.fitflow_cfg = cfg;
msg.url     = cfg.base_url + '/api/webhooks/nodered';
msg.method  = 'POST';
msg.headers = { 'x-webhook-secret': cfg.secret, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({ action: 'get_pending_recipients', limit: 20 });
return msg;

if (!msg.payload || !msg.payload.ok ||
    !msg.payload.recipients ||
    msg.payload.recipients.length === 0) {
  node.status({ fill: 'grey', shape: 'ring', text: 'antrian kosong' });
  return null;
}
node.status({ fill: 'blue', shape: 'dot', text: msg.payload.recipients.length + ' pending' });
msg.payload = msg.payload.recipients;
return msg;

const cfg = msg.fitflow_cfg || global.get('fitflow') || {};
const recipient = msg.payload;

const bc = Array.isArray(recipient.broadcast)
  ? recipient.broadcast[0]
  : recipient.broadcast;

msg.recipientId = recipient.id;
msg.fitflow_cfg = cfg;

let phone = (recipient.phone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

msg.url     = 'https://api.fonnte.com/send';
msg.method  = 'POST';
msg.headers = { 'Authorization': cfg.fonnte_token, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
  target:      phone,
  message:     bc ? bc.content : '(pesan kosong)',
  countryCode: '62'
});
return msg;

const cfg = msg.fitflow_cfg || global.get('fitflow') || {};
const ok  = msg.statusCode === 200 && msg.payload && msg.payload.status === true;

node.status({ fill: ok ? 'green' : 'red', shape: 'dot', text: ok ? '✅ sent' : '❌ failed' });

msg.url     = cfg.base_url + '/api/webhooks/nodered';
msg.method  = 'POST';
msg.headers = { 'x-webhook-secret': cfg.secret, 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
  action:       'mark_recipient',
  recipient_id: msg.recipientId,
  status:       ok ? 'sent' : 'failed'
});
return msg;

const cfg = global.get('fitflow') || {};

// Supabase DB Webhook format: { type, table, record: {...} }
const body   = msg.payload;
const record = (body && body.record) ? body.record : body;

if (!record || !record.registrant_name) {
  msg.payload    = JSON.stringify({ ok: false, error: 'payload tidak valid' });
  msg.statusCode = 400;
  return [null, msg];
}

const rupiah = n => 'Rp ' + Number(n || 0).toLocaleString('id-ID');
const nama   = record.registrant_name  || '?';
const telp   = record.registrant_phone || '-';
const tier   = record.tier === 'early_bird' ? 'Early Bird 🔥' : 'OTS';
const bukti  = record.proof_url
  ? '\n📎 Bukti: ' + record.proof_url
  : '\n⚠️ Bukti belum diupload';

const pesan =
  '🎉 *Pendaftaran Baru!*\n\n' +
  '👤 *Nama:* ' + nama + '\n' +
  '📱 *HP:* ' + telp + '\n' +
  '🎟️ *Tier:* ' + tier + '\n' +
  '💰 *Bayar:* ' + rupiah(record.amount_paid) +
  bukti + '\n\n' +
  '👉 Konfirmasi di: ' + cfg.base_url + '/events';

let phone = (cfg.instr_phone || '').replace(/\D/g, '');
if (phone.startsWith('0')) phone = '62' + phone.slice(1);

// Output 1: kirim WA ke instruktur
const waMsg = {
  method:  'POST',
  headers: { 'Authorization': cfg.fonnte_token, 'Content-Type': 'application/json' },
  url:     'https://api.fonnte.com/send',
  payload: JSON.stringify({ target: phone, message: pesan, countryCode: '62' })
};

// Output 2: balas 200 OK ke Supabase segera
msg.payload    = JSON.stringify({ ok: true });
msg.statusCode = 200;
msg.headers    = { 'Content-Type': 'application/json' };

return [waMsg, msg];

const cfg  = global.get('fitflow') || {};
const body = msg.payload;

// Output 1: langsung balas 200 OK ke Fonnte (cegah retry)
const resp = { ...msg };
resp.statusCode = 200;
resp.payload    = JSON.stringify({ ok: true });
resp.headers    = { 'Content-Type': 'application/json' };

// Output 2: forward ke FitFlow - tambahkan instructor_id dari config
const fwd = {
  method:  'POST',
  headers: { 'Content-Type': 'application/json' },
  url:     cfg.base_url + '/api/wa/incoming?key=' + encodeURIComponent(cfg.fonnte_key),
  payload: JSON.stringify({ ...body, instructor_id: cfg.user_id })
};

return [resp, fwd];
